const items = $input.all();
const all = [];

// Lost deals
items.filter(i => i.json.properties?.closed_lost_reason).forEach(d => {
  const reason = d.json.properties?.closed_lost_reason?.value || '';
  if (reason.length > 5) all.push({ source:'lost_deal', text: reason, value: parseFloat(d.json.properties?.amount?.value || 0) });
});

// NPS verbatims
(items.find(i => Array.isArray(i.json))?.json || []).filter(r => r.comment).forEach(r => {
  all.push({ source:'nps', text: r.comment, value: 0, score: r.score });
});

// Support tickets
items.filter(i => i.json.properties?.subject).forEach(t => {
  const text = (t.json.properties?.subject?.value || '') + ': ' + (t.json.properties?.content?.value || '');
  all.push({ source:'support', text: text.slice(0,300), value: 0 });
});

return [{ json: { feedback: all, count: all.length, week: new Date().toLocaleDateString('en-GB') } }];

let classified;
try { classified = JSON.parse($json.message.content); } catch(e) {
  const match = $json.message.content.match(/\[.*\]/s);
  classified = match ? JSON.parse(match[0]) : [];
}

const feedback = $('Normalise Feedback').first().json.feedback;
const THRESHOLD = parseFloat($env.JIRA_THRESHOLD || '5000');

const themes = {};
classified.forEach(item => {
  const f = feedback[item.index];
  if (!f) return;
  const t = item.theme;
  if (!themes[t]) themes[t] = { theme: t, count: 0, total_value: 0, urgency_sum: 0, retention_risk_count: 0, quotes: [] };
  themes[t].count++;
  themes[t].total_value += f.value || 0;
  themes[t].urgency_sum += item.urgency;
  if (item.is_retention_risk) themes[t].retention_risk_count++;
  if (themes[t].quotes.length < 3) themes[t].quotes.push(f.text.slice(0,100));
});

const ranked = Object.values(themes)
  .map(t => ({ ...t, avg_urgency: (t.urgency_sum/t.count).toFixed(1), impact_score: Math.round(t.total_value * 0.5 + t.count * 200 + t.retention_risk_count * 1000) }))
  .sort((a,b) => b.impact_score - a.impact_score)
  .filter(t => t.impact_score >= THRESHOLD);

return ranked.map(t => ({ json: t }));
